#define OFFSET 100000
#define MAXN 300000

int parent[MAXN];

int find(int x) {
    if (parent[x] == x)
        return x;
    return parent[x] = find(parent[x]);
}

void unite(int a, int b) {
    a = find(a);
    b = find(b);
    if (a != b)
        parent[b] = a;
}

int maxStonesRemoved(int stones[][2], int n) {
    // Initialize DSU
    for (int i = 0; i < MAXN; i++)
        parent[i] = -1;

    // Union rows and columns
    for (int i = 0; i < n; i++) {
        int r = stones[i][0];
        int c = stones[i][1] + OFFSET;

        if (parent[r] == -1) parent[r] = r;
        if (parent[c] == -1) parent[c] = c;

        unite(r, c);
    }

    // Count components using stones only
    int compCount = 0;
    int seen[MAXN] = {0};

    for (int i = 0; i < n; i++) {
        int root = find(stones[i][0]);
        if (!seen[root]) {
            seen[root] = 1;
            compCount++;
        }
    }

    return n - compCount;
}

