class Solution {

    private Map<Integer, Integer> parent = new HashMap<>();

    private int find(int x) {
        if (parent.get(x) != x) {
            parent.put(x, find(parent.get(x)));
        }
        return parent.get(x);
    }

    private void union(int a, int b) {
        int pa = find(a);
        int pb = find(b);
        if (pa != pb) {
            parent.put(pb, pa);
        }
    }

    public int maxStonesRemoved(int[][] stones) {
        parent.clear();
        final int OFFSET = 100000;  // separate rows and columns

        // Union row and column for each stone
        for (int[] s : stones) {
            int r = s[0];
            int c = s[1] + OFFSET;

            parent.putIfAbsent(r, r);
            parent.putIfAbsent(c, c);

            union(r, c);
        }

        // Count components via stones only
        Set<Integer> components = new HashSet<>();
        for (int[] s : stones) {
            components.add(find(s[0]));
        }

        return stones.length - components.size();
    }
}

