class Solution {
    constructor() {
        this.parent = new Map();
    }

    find(x) {
        if (this.parent.get(x) !== x) {
            this.parent.set(x, this.find(this.parent.get(x)));
        }
        return this.parent.get(x);
    }

    union(a, b) {
        let pa = this.find(a);
        let pb = this.find(b);
        if (pa !== pb) {
            this.parent.set(pb, pa);
        }
    }

    maxStonesRemoved(stones) {
        this.parent.clear();
        const OFFSET = 100000; // separate rows & columns

        // Union rows and columns
        for (const [x, y] of stones) {
            const r = x;
            const c = y + OFFSET;

            if (!this.parent.has(r)) this.parent.set(r, r);
            if (!this.parent.has(c)) this.parent.set(c, c);

            this.union(r, c);
        }

        // Count components via stones only
        const components = new Set();
        for (const [x, _] of stones) {
            components.add(this.find(x));
        }

        return stones.length - components.size;
    }
}
